namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
            Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
            Ratings = [5, 4, 5, 4, 5]
        },
        new()
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Ingredients = "Spaghetti\nGuanciale (or pancetta)\nEgg yolks\nPecorino Romano\nBlack pepper",
            Steps = "1. Cook spaghetti in salted water until al dente.\n2. Crisp guanciale in a pan over medium heat.\n3. Whisk egg yolks with grated Pecorino and pepper.\n4. Toss hot pasta with guanciale and remove from heat.\n5. Stir in egg mixture quickly, tossing to coat.\n6. Serve immediately with extra Pecorino.",
            Ratings = [5, 5, 4]
        },
        new()
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nCanned tomatoes\nHeavy cream\nOnion\nGarlic\nGinger",
            Steps = "1. Marinate chicken in yogurt and spices for at least 1 hour.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger in a pot.\n4. Add tomatoes and simmer for 15 minutes.\n5. Stir in cream and add the cooked chicken.\n6. Simmer for 10 minutes and serve with rice or naan.",
            Ratings = [5, 4, 5, 5]
        },
        new()
        {
            Id = 4, Title = "Vegetable Samosas", Category = "Indian",
            Ingredients = "Potatoes\nGreen peas\nCumin seeds\nCoriander\nGaram masala\nPastry dough\nOil for frying",
            Steps = "1. Boil and mash potatoes.\n2. Sauté cumin seeds, add peas and spices.\n3. Mix with mashed potatoes and let cool.\n4. Cut dough into circles, fill and fold into triangles.\n5. Deep fry at 350°F until golden brown.\n6. Serve with mint chutney.",
            Ratings = [4, 4, 5]
        },
        new()
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa",
            Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan.\n4. Fill tortillas with seasoned beef.\n5. Top with lettuce, tomato, cheese, sour cream, and salsa.",
            Ratings = [4, 5, 4, 4]
        },
        new()
        {
            Id = 6, Title = "Guacamole", Category = "Mexican",
            Ingredients = "Avocados\nLime juice\nCilantro\nRed onion\nJalapeño\nTomato\nSalt",
            Steps = "1. Halve avocados and remove pits.\n2. Mash avocado in a bowl to desired consistency.\n3. Stir in diced onion, tomato, jalapeño, and cilantro.\n4. Add lime juice and salt to taste.\n5. Serve immediately with tortilla chips.",
            Ratings = [5, 5, 5, 4, 5]
        },
        new()
        {
            Id = 7, Title = "Chocolate Lava Cake", Category = "Desserts",
            Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract",
            Steps = "1. Preheat oven to 425°F (220°C).\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick.\n4. Fold chocolate mixture into eggs, then fold in flour.\n5. Pour into greased ramekins.\n6. Bake for 12-14 minutes — centers should be soft.\n7. Invert onto plates and serve immediately.",
            Ratings = [5, 5, 5]
        },
        new()
        {
            Id = 8, Title = "Classic Cheesecake", Category = "Desserts",
            Ingredients = "Cream cheese\nSugar\nEggs\nVanilla extract\nSour cream\nGraham cracker crust",
            Steps = "1. Preheat oven to 325°F (165°C).\n2. Beat cream cheese and sugar until smooth.\n3. Add eggs one at a time, then vanilla and sour cream.\n4. Pour filling into crust.\n5. Bake for 55-60 minutes until edges are set.\n6. Cool slowly in the oven with door ajar.\n7. Refrigerate at least 4 hours before serving.",
            Ratings = [4, 5, 4, 5]
        },
        new()
        {
            Id = 9, Title = "Miso Ramen", Category = "Japanese",
            Ingredients = "Ramen noodles\nMiso paste\nChicken broth\nSoy sauce\nSesame oil\nSoft-boiled egg\nGreen onions\nCorn\nChashu pork",
            Steps = "1. Bring chicken broth to a simmer.\n2. Whisk in miso paste, soy sauce, and sesame oil.\n3. Cook ramen noodles according to package.\n4. Place noodles in bowls and ladle broth over them.\n5. Top with sliced chashu, soft-boiled egg, corn, and green onions.",
            Ratings = [5, 4, 5]
        },
        new()
        {
            Id = 10, Title = "Teriyaki Salmon", Category = "Japanese",
            Ingredients = "Salmon fillets\nSoy sauce\nMirin\nSake\nSugar\nGinger\nSesame seeds\nSteamed rice",
            Steps = "1. Mix soy sauce, mirin, sake, and sugar for teriyaki glaze.\n2. Pan-sear salmon skin-side down for 3 minutes.\n3. Flip and pour glaze into the pan.\n4. Cook 3-4 more minutes, spooning glaze over salmon.\n5. Serve over steamed rice, garnished with sesame seeds.",
            Ratings = [5, 5, 4, 4]
        }
    ];

    private int _nextId = 11;

    public IReadOnlyList<Recipe> GetAll() => _recipes.AsReadOnly();

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().Order().ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }

    public Recipe Add(Recipe recipe)
    {
        recipe.Id = _nextId++;
        _recipes.Add(recipe);
        return recipe;
    }
}
"}

