@page "/category/{CategoryName}"
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 g-4 mt-1">
        @foreach (var recipe in recipes)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text text-muted">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> recipes = [];

    protected override void OnInitialized()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeHub</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (recipe is not null)
        {
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        }
    </ol>
</nav>

@if (recipe is null)
{
    <h1>Recipe Not Found</h1>
    <p>Sorry, we couldn't find that recipe.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <div class="row mt-3">
        <div class="col-md-4">
            <div class="card mb-3">
                <div class="card-header"><strong>🥘 Ingredients</strong></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>
        <div class="col-md-8">
            <div class="card mb-3">
                <div class="card-header"><strong>📝 Steps</strong></div>
                <div class="card-body">
                    @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                    {
                        <p>@step</p>
                    }
                </div>
            </div>
        </div>
    </div>

    <div class="card mt-2">
        <div class="card-body">
            <h5>Rate this recipe</h5>
            <p class="text-muted mb-2">
                @if (recipe.RatingCount > 0)
                {
                    <span>⭐ @recipe.AverageRating.ToString("F1") — @recipe.RatingCount rating(s)</span>
                }
                else
                {
                    <span>No ratings yet. Be the first!</span>
                }
            </p>
            <StarRating RecipeId="@recipe.Id" />
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService

@if (submitted)
{
    <div class="text-success fw-bold">✓ Thank you for your @selectedRating-star rating!</div>
}
else
{
    <div class="d-flex align-items-center gap-1 star-rating">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <button type="button"
                    class="btn btn-link p-0 fs-4 text-decoration-none @(star <= (hoveredStar > 0 ? hoveredStar : selectedRating) ? "text-warning" : "text-secondary")"
                    @onclick="() => SubmitRating(star)"
                    @onmouseover="() => hoveredStar = star"
                    @onmouseout="() => hoveredStar = 0"
                    title="@star star(s)">
                ★
            </button>
        }
    </div>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int hoveredStar;
    private int selectedRating;
    private bool submitted;

    private void SubmitRating(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        submitted = true;
