@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe — RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success">
        @successMessage
        <a href="recipe/@createdId">View your recipe →</a>
    </div>
}

<EditForm Model="recipe" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="recipe.Title" placeholder="e.g. Grandma's Apple Pie" />
        <ValidationMessage For="() => recipe.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="recipe.Category">
            <option value="">— Select a category —</option>
            @foreach (var cat in categories)
            {
                <option value="@cat">@cat</option>
            }
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => recipe.Category" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients</label>
        <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="recipe.Ingredients"
                       placeholder="One ingredient per line" />
        <ValidationMessage For="() => recipe.Ingredients" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Preparation Steps</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="recipe.Steps"
                       placeholder="Describe each step on a new line" />
        <ValidationMessage For="() => recipe.Steps" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private Recipe recipe = new();
    private IReadOnlyList<string> categories = [];
    private string? successMessage;
    private int createdId;

    protected override void OnInitialized()
    {
        categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        var created = RecipeService.Add(recipe);
        createdId = created.Id;
        successMessage = $""{created.Title}" has been submitted successfully!";
        recipe = new();
    }
}

